import { packageJsonParser } from "./parsers/package-json.js";
import { pubspecParser } from "./parsers/pubspec.js";
import type { ManifestParser } from "./parsers/types.js";
import { printBanner } from "./banner.js";
import { RED, RESET } from "./output.js";
import { VERSION } from "./version.js";

// Parser registry — add new ecosystem parsers here
const parsers = new Map<string, ManifestParser>([
  [packageJsonParser.manifestName, packageJsonParser],
  [pubspecParser.manifestName, pubspecParser],
]);

/** Extract the value following a --flag from the args list */
function getFlagValue(args: readonly string[], flag: string): string | undefined {
  const idx = args.indexOf(flag);
  if (idx === -1 || idx + 1 >= args.length) {
    return undefined;
  }
  return args[idx + 1];
}

const HELP = `
mido — cross-ecosystem monorepo workspace tool

Usage:
  mido <command> [options]

Commands:
  init              Scan repo and generate mido.yml
  install           Install git hooks
  check             Run all workspace consistency checks
  check --fix       Interactively resolve version mismatches and update mido.lock
  check --quiet     Silent mode — only output on failure (for hooks)
  dev [--verbose]   Watch bridges and regenerate on changes
  lint              Run linters across all packages
  lint --fix        Auto-fix lint issues
  fmt               Format all packages
  fmt --check       Check formatting without fixing
  build             Build all packages
  pre-commit        Run full pre-commit validation suite
  commit-msg <file> Validate a commit message (used by git hooks)
  help              Show this help message

Flags (lint, fmt, build):
  --quiet              Only show failures
  --package <path>     Target a specific package

Flags (lint, fmt):
  --ecosystem <name>   Target a specific ecosystem (typescript, dart)

Config:
  mido.yml          Workspace config (searched upward from cwd)
  mido.lock         Resolved version policy (auto-generated by --fix)

Options:
  --help, -h       Show help
  --version, -v    Show version
`;

async function main(): Promise<void> {
  const args = process.argv.slice(2);
  const command = args[0];

  if (!command || command === "help" || command === "--help" || command === "-h") {
    printBanner();
    console.log(HELP);
    process.exit(0);
  }

  if (command === "--version" || command === "-v") {
    console.log(VERSION);
    process.exit(0);
  }

  if (command === "check") {
    const fix = args.includes("--fix");
    const quiet = args.includes("--quiet") || args.includes("--hook");
    const { runCheck } = await import("./commands/check.js");
    const exitCode = await runCheck(parsers, { fix, quiet });
    process.exit(exitCode);
  }

  if (command === "init") {
    const { runInit } = await import("./commands/init.js");
    const exitCode = await runInit(process.cwd(), parsers);
    process.exit(exitCode);
  }

  if (command === "dev") {
    const verbose = args.includes("--verbose");
    const { runDev } = await import("./watcher/dev.js");
    const exitCode = await runDev(parsers, { verbose });
    process.exit(exitCode);
  }

  if (command === "install") {
    const { runInstall } = await import("./commands/install.js");
    const exitCode = await runInstall(process.cwd());
    process.exit(exitCode);
  }

  if (command === "lint") {
    const fix = args.includes("--fix");
    const quiet = args.includes("--quiet");
    const pkg = getFlagValue(args, "--package");
    const ecosystem = getFlagValue(args, "--ecosystem");
    const { runLint } = await import("./commands/lint.js");
    const exitCode = await runLint(parsers, { fix, quiet, package: pkg, ecosystem });
    process.exit(exitCode);
  }

  if (command === "fmt") {
    const check = args.includes("--check");
    const quiet = args.includes("--quiet");
    const pkg = getFlagValue(args, "--package");
    const ecosystem = getFlagValue(args, "--ecosystem");
    const { runFmt } = await import("./commands/fmt.js");
    const exitCode = await runFmt(parsers, { check, quiet, package: pkg, ecosystem });
    process.exit(exitCode);
  }

  if (command === "build") {
    const quiet = args.includes("--quiet");
    const pkg = getFlagValue(args, "--package");
    const { runBuild } = await import("./commands/build.js");
    const exitCode = await runBuild(parsers, { quiet, package: pkg });
    process.exit(exitCode);
  }

  if (command === "pre-commit") {
    const { runPreCommit } = await import("./commands/pre-commit.js");
    const exitCode = await runPreCommit(parsers);
    process.exit(exitCode);
  }

  if (command === "commit-msg") {
    const filePath = args[1];
    if (!filePath) {
      console.error("Usage: mido commit-msg <file>");
      process.exit(1);
    }
    const { runCommitMsg } = await import("./commands/commit-msg.js");
    const exitCode = await runCommitMsg(filePath);
    process.exit(exitCode);
  }

  console.error(`Unknown command: ${command}\nRun "mido help" for usage.`);
  process.exit(1);
}

main().catch((error: unknown) => {
  // CancelError from @clack/prompts cancel flow — exit cleanly
  if (error instanceof Error && error.name === "CancelError") {
    process.exit(0);
  }
  const message = error instanceof Error ? error.message : String(error);
  console.error(`${RED}error:${RESET} ${message}`);
  process.exit(1);
});
